@staticmethod
def _canned_policy(resource, expires):
    """
    Creates a canned policy string.
    """
    return json.dumps({
        "Statement": [{
            "Resource": resource,
            "Condition": {
                "DateLessThan": {"AWS:EpochTime": expires}
            }
        }]
    }, separators=(',', ':'))

@staticmethod
def _custom_policy(resource, expires=None, valid_after=None, ip_address=None):
    """
    Creates a custom policy string.
    """
    condition = {}
    if expires is not None:
        condition["DateLessThan"] = {"AWS:EpochTime": expires}
    if valid_after is not None:
        condition["DateGreaterThan"] = {"AWS:EpochTime": valid_after}
    if ip_address is not None:
        condition["IpAddress"] = {"AWS:SourceIp": ip_address}

    return json.dumps({
        "Statement": [{
            "Resource": resource,
            "Condition": condition
        }]
    }, separators=(',', ':'))

@staticmethod
def _url_base64_encode(data):
    """
    Base64 encode data for use in a URL.
    """
    if isinstance(data, six.text_type):
        data = data.encode('utf-8')
    encoded = base64.b64encode(data)
    if isinstance(encoded, bytes):
        encoded = encoded.decode('utf-8')
    return encoded.replace('+', '-').replace('=', '_').replace('/', '~')

@staticmethod
def _sign_string(policy, private_key_file=None, private_key_string=None):
    """
    Sign a policy string using RSA-SHA1.
    """
    if private_key_file and private_key_string:
        raise ValueError("Only one of private_key_file or private_key_string can be provided")

    if private_key_file is not None:
        if hasattr(private_key_file, 'read'):
            private_key_string = private_key_file.read()
        else:
            with open(private_key_file, 'rb') as fp:
                private_key_string = fp.read()

    if isinstance(private_key_string, six.text_type):
        private_key_string = private_key_string.encode('utf-8')
    if isinstance(policy, six.text_type):
        policy = policy.encode('utf-8')

    key = rsa.PrivateKey.load_pkcs1(private_key_string)
    return rsa.sign(policy, key, 'SHA-1')

