class TextProtocol(object):
    """UTF-8 encode ``key`` and ``value`` (unicode strings) and join them
    with a tab character. When reading input, we fall back to latin-1 if
    we can't UTF-8 decode the line.

    If ``key`` or ``value`` is ``None``, don't include a tab. When decoding a
    line with no tab in it, ``value`` will be ``None``.

    When reading from a line with multiple tabs, we break on the first one.

    Your key should probably not be ``None`` or have tab characters in it, but
    we don't check.
    """
    def read(self, line):
        if not PY2 and isinstance(line, bytes):
            try:
                line = line.decode('utf_8')
            except UnicodeDecodeError:
                line = line.decode('latin_1')

        if '\t' in line:
            key, value = line.split('\t', 1)
        else:
            key, value = line, None

        return (key, value)

    def write(self, key, value):
        if key is None:
            line = value
        elif value is None:
            line = key
        else:
            line = '%s\t%s' % (key, value)

        if PY2:
            return line.encode('utf_8') if isinstance(line, unicode) else line
        else:
            return line.encode('utf_8')

class IntStreamer(object):

    @classmethod
    def int_from_script_bytes(class_, s, require_minimal=False):
        from pycoin.coins.SolutionChecker import ScriptError
        from . import errno
        if len(s) == 0:
            return 0
        s = bytearray(s)
        s.reverse()
        i = s[0]
        v = i & 0x7f
        if require_minimal:
            if v == 0:
                if len(s) <= 1 or ((s[1] & 0x80) == 0):
                    raise ScriptError("non-minimally encoded", errno.UNKNOWN_ERROR)
        is_negative = ((i & 0x80) > 0)
        for b in s[1:]:
            v <<= 8
            v += b
        if is_negative:
            v = -v
        return v

    @classmethod
    def int_to_script_bytes(class_, v):
        if v == 0:
            return b""
        is_negative = v < 0
        if is_negative:
            v = -v
        result = bytearray()
        while v:
            result.append(v & 0xff)
            v >>= 8
        if result[-1] & 0x80:
            result.append(0x80 if is_negative else 0x00)
        elif is_negative:
            result[-1] |= 0x80
        result.reverse()
        return bytes(result)

