    if permissions is None:
        return "+all"

    if not permissions:
        return ""

    # If every permission is explicitly prefixed, just join them as-is.
    if all(permission.startswith(("+", "-")) for permission in permissions):
        return ",".join(permissions)

    additions = []
    removals = []

    provided = set()
    for permission in permissions:
        if permission.startswith(("+", "-")):
            # Mixed prefixed/unprefixed input is not described; preserve prefixed items.
            additions.append(permission)
        else:
            additions.append(f"+{permission}")
