class SimplexTransform(RVTransform):
    name = "simplex"

    def forward(self, value, *inputs):
        value = pt.as_tensor_variable(value)
        # Map a simplex vector of length K to unconstrained space of length K-1
        return pt.log(value[..., :-1]) - pt.log(value[..., -1][..., None])

    def backward(self, value, *inputs):
        value = pt.as_tensor_variable(value)
        # Inverse of the additive log-ratio transform
        exp_value = pt.exp(value)
        denom = 1 + pt.sum(exp_value, axis=-1, keepdims=True)
        simplex_part = exp_value / denom
        last_part = 1 / denom
        return pt.concatenate([simplex_part, last_part], axis=-1)

    def log_jac_det(self, value, *inputs):
        value = pt.as_tensor_variable(value)
        # Jacobian determinant for the inverse transform
        return pt.sum(pt.log(value), axis=-1)

class TaskPool:
    """
    Coroutine worker pool with limits on the maximum number of coroutines.
    """

    def __init__(self, *, max_tasks=None, default_limit=None, logger=None):
        super().__init__()
        if logger is None:
            logger = logging.getLogger(__name__)
        self._logger = logger
        self._group_limits = {}
        self._group_tasks = {}
        self.default_limit = default_limit
        self.set_limit((), max_tasks)

    def set_limit(self, group, new_limit):
        if new_limit is None:
            self._group_limits.pop(group, None)
            return

        if new_limit < 0:
            raise ValueError("new_limit must be non-negative or None")

        self._group_limits[group] = new_limit

    def clear_limit(self, group):
        self._group_limits.pop(group, None)

    def get_limit(self, group):
        return self._group_limits.get(group)

    def get_task_count(self, group):
        return self._group_tasks.get(group, 0)

    def add(self, groups, coro):
        # Normalize groups and ensure implicit group is always included.
        groups = set(groups)
        groups.add(())

        # Check all limits first, without modifying state.
        for group in groups:
            limit = self._group_limits.get(group, self.default_limit)
            if limit is not None and self._group_tasks.get(group, 0) >= limit:
                raise RuntimeError(f"task limit exhausted for group {group!r}")

        # Create task only after all checks pass.
        task = asyncio.create_task(coro)

        # Register task in all groups.
        for group in groups:
            self._group_tasks[group] = self._group_tasks.get(group, 0) + 1

        def _done_callback(_task):
            for group in groups:
                count = self._group_tasks.get(group, 0) - 1
                if count <= 0:
                    self._group_tasks.pop(group, None)
                else:
                    self._group_tasks[group] = count

        task.add_done_callback(_done_callback)
        return task

    def spawn(self, __groups, __coro_fun, *args, **kwargs):
        # ensure the implicit group is included
        groups = set(__groups)
        groups.add(())
        coro = __coro_fun(*args, **kwargs)
        return self.add(groups, coro)

