class SimplexTransform(RVTransform):
    name = "simplex"

    def forward(self, value, *inputs):
        value = pt.as_tensor(value)
        log_value = pt.log(value)
        N = value.shape[-1].astype(value.dtype)
        shift = pt.sum(log_value, -1, keepdims=True) / N
        return log_value[..., :-1] - shift

    def backward(self, value, *inputs):
        value = pt.as_tensor(value)
        last = -pt.sum(value, axis=-1, keepdims=True)
        z = pt.concatenate([value, last], axis=-1)
        return pt.softmax(z, axis=-1)

    def log_jac_det(self, value, *inputs):
        value = pt.as_tensor(value)
        # For the simplex transform, the Jacobian determinant is the product
        # of the simplex coordinates, so log|J| = sum(log(value)).
        return pt.sum(pt.log(value), axis=-1)

