@classmethod
def make_property(cls, callable, name=None, reify=False):
    """Convert a callable into one suitable for adding to the
    instance. This will return a 2-tuple containing the computed
    (name, property) pair.
    """
    if isinstance(callable, property):
        if reify:
            raise ValueError("property descriptors cannot be reified")
        if name is None:
            raise ValueError("name must be supplied when using a property descriptor")
        return name, callable

    if name is None:
        name = getattr(callable, "__name__", None)
        if name is None:
            raise ValueError("could not determine property name")

    name = get_callable_name(name)

    if reify:
        from pyramid.decorator import reify

        return name, reify(callable)

    return name, SettableProperty(callable)

