# in PEP 380, with modifications to capture the value sent during yield
try:
    _i = iter(receiver)
    try:
        _y = next(_i)
    except StopIteration as _e:
        return _e.value

    while True:
        try:
            _s = yield _y
        except GeneratorExit:
            dest.clear()
            try:
                _close = _i.close
            except AttributeError:
                pass
            else:
                _close()
            raise
        except BaseException as _e:
            try:
                _m = _i.throw
            except AttributeError:
                dest.clear()
                raise
            else:
                try:
                    _y = _m(type(_e), _e, _e.__traceback__)
                except StopIteration as _e2:
                    return _e2.value
        else:
            dest.append(_s)
            try:
                _y = _i.send(_s)
            except StopIteration as _e:
                return _e.value
