text = add_surrogate(text)
entities = list(entities or [])

if not entities:
    return escape(del_surrogate(text))

# Sort entities by offset, and for equal offsets by longer ones first.
entities.sort(key=lambda e: (e.offset, -e.length))

# Build insertion points for opening/closing tags.
opens = {}
closes = {}

for e in entities:
    opener = closer = None

    formatter = ENTITY_TO_FORMATTER.get(type(e))
    if formatter:
        opener, closer = formatter(e, del_surrogate(text[e.offset:e.offset + e.length]))
    elif isinstance(e, MessageEntityMentionName):
        opener, closer = ENTITY_TO_FORMATTER[MessageEntityMentionName](e, '')
    elif isinstance(e, MessageEntityTextUrl):
        opener, closer = ENTITY_TO_FORMATTER[MessageEntityTextUrl](e, '')
    elif isinstance(e, MessageEntityUrl):
        opener, closer = ENTITY_TO_FORMATTER[MessageEntityUrl](e, del_surrogate(text[e.offset:e.offset + e.length]))
    elif isinstance(e, MessageEntityEmail):
        opener, closer = ENTITY_TO_FORMATTER[MessageEntityEmail](e, del_surrogate(text[e.offset:e.offset + e.length]))
    elif isinstance(e, MessageEntityPre):
        opener, closer = ENTITY_TO_FORMATTER[MessageEntityPre](e, del_surrogate(text[e.offset:e.offset + e.length]))
    else:
        continue

    opens.setdefault(e.offset, []).append(opener)
    closes.setdefault(e.offset + e.length, []).insert(0, closer)

result = []
for i, ch in enumerate(text):
    if i in opens:
        result.extend(opens[i])
    result.append(escape(del_surrogate(ch)))
    if i + 1 in closes:
        result.extend(closes[i + 1])

if len(text) in closes:
    result.extend(closes[len(text)])

return ''.join(result)

