@contextmanager
def temporary_assignment(obj, attr, value):
    """Temporarily assign obj.attr to value."""
    had_attr = hasattr(obj, attr)
    if had_attr:
        old_value = getattr(obj, attr)
    try:
        setattr(obj, attr, value)
        yield
    finally:
        if had_attr:
