def perform_checkpoint(self, reopen_wal: bool = False):
    """Apply committed WAL pages to the main file and optionally reopen WAL."""
    for page, page_data in self._wal.checkpoint():
        start = page * self._tree_conf.page_size
        self._fd.seek(start)
        write_to_file(self._fd, self._dir_fd, page_data, fsync=False)

    fsync_file_and_dir(self._fd.fileno(), self._dir_fd)
    self._cache.clear()

