@staticmethod
def merge(files, accumulate=True):
    """Merge metrics from given mmap files.

    By default, histograms are accumulated, as per prometheus wire format.
    But if writing the merged data back to mmap files, use
    accumulate=False to avoid compound accumulation.
    """
    metrics = {}

    def get_metric(name, documentation, typ, unit=''):
        key = (name, documentation, typ, unit)
        if key not in metrics:
            metrics[key] = Metric(name, documentation, typ, unit)
        return metrics[key]

    for f in files:
        for key, value, timestamp in MmapedDict.read_all_values_from_file(f):
            parts = key.split(':', 4)
            if len(parts) != 5:
                continue

            metric_type, metric_name, name, labels_json, extra = parts
            labels = json.loads(labels_json) if labels_json else {}

            # Gauge values
            if metric_type == 'gauge':
                m = get_metric(metric_name, '', 'gauge')
                m.add_sample(name, labels, value, timestamp)
                continue

            # Counter values
            if metric_type == 'counter':
                m = get_metric(metric_name, '', 'counter')
                m.add_sample(name, labels, value, timestamp)
                continue

            # Summary values
            if metric_type == 'summary':
                m = get_metric(metric_name, '', 'summary')
                m.add_sample(name, labels, value, timestamp)
                continue

            # Histogram values
            if metric_type == 'histogram':
                m = get_metric(metric_name, '', 'histogram')
                m.add_sample(name, labels, value, timestamp)
                continue

    return list(metrics.values())

