def _asdict_inner(value):
    if is_dataclass(value) and not isinstance(value, type):
        return {field.name: _asdict_inner(getattr(value, field.name)) for field in fields(value)}
    elif isinstance(value, tuple) and hasattr(value, "_fields"):  # namedtuple
        return type(value)(*[_asdict_inner(v) for v in value])
    elif isinstance(value, (list, tuple)):
        return type(value)(_asdict_inner(v) for v in value)
    elif isinstance(value, dict):
        return type(value)((_asdict_inner(k), _asdict_inner(v)) for k, v in value.items())
    else:
        return copy.deepcopy(value)

