@stored_property
def dependencies(self):
    """Run's the files' linker iteratively and returns a set of all library dependencies."""
    dependencies = set()
    to_process = set(self.find_direct_dependencies())

    while to_process:
        dependency = to_process.pop()
        if dependency in dependencies:
            continue

        dependencies.add(dependency)

        # Only ELF files can have further dependencies.
        if dependency.elf:
            for child_dependency in dependency.elf.find_direct_dependencies():
                if child_dependency not in dependencies:
                    to_process.add(child_dependency)

    return dependencies

