    # one PowerPoint document stream.
    stream_names = []
    try:
        stream_names = ppt.listdir(streams=True, storages=False)
    except Exception:
        return False

    # Normalize stream names for easier checks
    normalized = ['/'.join(name) for name in stream_names]

    has_current_user = any(
        name.lower().endswith('current user') or
        name.lower().endswith('currentuser')
        for name in normalized
    )

    # Typical PPT document streams are "PowerPoint Document" or similar.
    has_ppt_stream = any(
        'powerpoint document' in name.lower()
        for name in normalized
    )

    if not (has_current_user and has_ppt_stream):
        return False

    # Try to parse the Current User stream if present; this is a strong
    # indicator that the file is a PPT OLE file.
    current_user_path = None
    for name in stream_names:
        joined = '/'.join(name)
        if joined.lower().endswith('current user') or joined.lower().endswith('currentuser'):
            current_user_path = name
            break

    if current_user_path is None:
        return False

    try:
        stream = ppt.openstream(current_user_path)
        parser = PptStream(stream)
        rec = parser.read_record()
        if not isinstance(rec, PptRecordCurrentUser):
            return False
    except Exception:
        return False

