@contextlib.contextmanager
def assertLoopErrorHandlerCalled(self, msg_re: str):
    pattern = re.compile(msg_re)
    old_handler = self.loop.get_exception_handler()
    called = []

    def handler(loop, context):
        called.append(context)
        if old_handler is not None:
            old_handler(loop, context)
        else:
            self.loop_exception_handler(loop, context)

    self.loop.set_exception_handler(handler)
    try:
        yield
    finally:
        self.loop.set_exception_handler(old_handler)

        if not called:
            self.fail(
                'loop exception handler was not called with a matching '
                'message')

        if not any(pattern.search(self._format_loop_exception(ctx, i + 1))
                   for i, ctx in enumerate(called)):
            formatted = '\n'.join(
                self._format_loop_exception(ctx, i + 1)
                for i, ctx in enumerate(called)
            )
            self.fail(
                'loop exception handler was called, but no message '
                'matched {!r}:\n{}'.format(msg_re, formatted))

