    current_paragraph = []

    def flush_paragraph():
        nonlocal current_heading, current_paragraph
        if current_heading or current_paragraph:
            paragraphs.append(
                Paragraph(
                    headings=[Heading(current_heading)] if current_heading else [],
                    sentences=self.tokenize_sentences(" ".join(current_paragraph)),
                )
            )
            current_heading = []
            current_paragraph = []

    for line in lines:
        stripped = line.strip()

        if not stripped:
            flush_paragraph()
            continue

        # Heading line: all uppercase and not too short/empty.
        if stripped.isupper() and current_paragraph == []:
            current_heading.append(stripped)
        else:
            current_paragraph.append(stripped)

    flush_paragraph()

    return Document(paragraphs)

