    for recipe_name in current:
        try:
            recipe = Recipe.get_recipe(recipe_name, ctx)
        except ValueError:
            continue

        for dep in recipe.depends:
            # Alternative dependency group: expand into multiple lists
            if isinstance(dep, (tuple, list)):
                new_expanded = []
                for dep_choice in dep:
                    for recipe_list in expanded:
                        if dep_choice in recipe_list:
                            new_expanded.append(recipe_list)
                        else:
                            new_list = list(recipe_list)
                            new_list.append(dep_choice)
                            new_expanded.append(new_list)
                expanded = new_expanded
                changed = True
            else:
                # Normal dependency: add to all lists if missing
                if dep not in seen:
                    for recipe_list in expanded:
                        recipe_list.append(dep)
                    seen.add(dep)
                    changed = True

# Remove duplicates while preserving order
unique = []
unique_keys = set()
for recipe_list in expanded:
    key = tuple(sorted(recipe_list))
    if key not in unique_keys:
        unique_keys.add(key)
        unique.append(recipe_list)

