class InvalidServerStringError(Exception):
    """Exception raised when SSLyze was unable to parse a hostname:port string supplied via the command line."""

    server_string: str
    error_message: str


class CommandLineServerStringParser:
    """Utility class to parse a 'host:port{ip}' string taken from the command line into a valid (host,ip, port) tuple.
    Supports IPV6 addresses.
    """

    SERVER_STRING_ERROR_BAD_PORT = "Not a valid host:port"

    @classmethod
    def parse_server_string(cls, server_str: str) -> Tuple[str, Optional[str], Optional[int]]:
        # Extract ip from target
        ip_address = None
        if "{" in server_str and server_str.endswith("}"):
            server_str, ip_address = server_str[:-1].split("{", 1)

        # IPv6 addresses are expected to be wrapped in []
        host = None
        port = None

        if server_str.startswith("["):
            # Format: [ipv6]:port
            if "]" not in server_str:
                raise InvalidServerStringError(cls.SERVER_STRING_ERROR_BAD_PORT)
            host_end = server_str.index("]")
            host = server_str[1:host_end]
            remainder = server_str[host_end + 1 :]
            if not remainder.startswith(":"):
                raise InvalidServerStringError(cls.SERVER_STRING_ERROR_BAD_PORT)
            port_str = remainder[1:]
        else:
            # Format: host:port
            if ":" not in server_str:
                raise InvalidServerStringError(cls.SERVER_STRING_ERROR_BAD_PORT)
            host, port_str = server_str.rsplit(":", 1)

        if not host:
            raise InvalidServerStringError(cls.SERVER_STRING_ERROR_BAD_PORT)

        try:
            port = int(port_str)
            if port < 1 or port > 65535:
                raise ValueError()
        except Exception:
            raise InvalidServerStringError(cls.SERVER_STRING_ERROR_BAD_PORT)

        return host, ip_address, port

