@classmethod
def from_func(cls, func):
    """Create a new FunctionBuilder instance based on an existing
    function. The original function will not be stored or
    modified.
    """
    # TODO: copy_body? gonna need a good signature regex.
    # TODO: might worry about __closure__?
    if isinstance(func, (classmethod, staticmethod)):
        func = func.__func__

    if not (inspect.isfunction(func) or inspect.ismethod(func) or
            isinstance(func, FunctionType)):
        raise TypeError('expected function or method, not %r' % (func,))

    if inspect.ismethod(func):
        func = func.__func__

    kwargs = cls._argspec_to_dict(func)
    kwargs.update({
        'name': func.__name__,
        'doc': func.__doc__,
        'module': getattr(func, '__module__', None),
        'dict': dict(getattr(func, '__dict__', {})),
        'annotations': dict(getattr(func, '__annotations__', {})),
    })

    # Python 3 only: preserve keyword-only defaults if present
    if not _IS_PY2:
        kwonlydefaults = kwargs.get('kwonlydefaults') or {}
        kwargs['kwonlydefaults'] = dict(kwonlydefaults)

    fb = cls(**kwargs)

    # Preserve async-ness where possible
    fb.is_async = inspect.iscoroutinefunction(func)
    return fb

def get_func(self, execdict=None, add_source=True, with_dict=True):
    """Compile and return a new function based on the current state."""
    if execdict is None:
        execdict = {}

    if self.indent < 1:
        raise ValueError('indent must be >= 1')

    body = self.body or 'pass'
    indent = ' ' * self.indent
    indented_body = '\n'.join(indent + line if line else line
                              for line in body.splitlines())

    src = 'def {name}{sig}:\n{body}\n'.format(
        name=self.name,
        sig=self.get_sig_str(),
        body=indented_body,
    )

    filename = self.filename
    compile_count = next(self._compile_count)
    code = compile(src, filename, 'exec')

    glb = dict(execdict)
    glb.setdefault('__name__', self.module or '__main__')
    loc = {}
    exec(code, glb, loc)
    func = loc[self.name]

    if add_source:
        func.__source__ = src

    if self.doc is not None:
        func.__doc__ = self.doc
    if self.module is not None:
        func.__module__ = self.module

    if with_dict and self.dict:
        func.__dict__.update(self.dict)

    if self.annotations and not _IS_PY2:
        func.__annotations__ = dict(self.annotations)

    return func

def add_arg(self, arg_name, default=inspect._empty):
    """Add an argument to the function signature."""
    if arg_name in self.args or arg_name in getattr(self, 'kwonlyargs', []):
        raise ExistingArgument(arg_name)

    if default is inspect._empty:
        self.args.append(arg_name)
    else:
        self.args.append(arg_name)
        defaults = list(self.defaults or ())
        defaults.append(default)
        self.defaults = tuple(defaults)

def remove_arg(self, arg_name):
    """Remove an argument from the function signature."""
    if arg_name in self.args:
        idx = self.args.index(arg_name)
        self.args.pop(idx)
        if self.defaults:
            num_required = len(self.args) - len(self.defaults)
            if idx >= num_required:
                defaults = list(self.defaults)
                del defaults[idx - num_required]
                self.defaults = tuple(defaults)
        return

    if not _IS_PY2 and arg_name in self.kwonlyargs:
        self.kwonlyargs.remove(arg_name)
        if self.kwonlydefaults and arg_name in self.kwonlydefaults:
            del self.kwonlydefaults[arg_name]
        return

    raise MissingArgument(arg_name)

