class CpuResource(Resource[float], resource_id="cpu"):
    @classmethod
    def from_spec(cls, spec: t.Any) -> float:
        """
        Convert spec to CpuResource.

        spec can be a float, int or string.
        - 1.0 -> 1.0
        - 1 -> 1.0
        - "1" -> 1.0
        - "10m" -> 0.01
        """
        if isinstance(spec, (int, float)):
            val = float(spec)
        elif isinstance(spec, str):
            spec = spec.strip()
            try:
                if spec.endswith("m"):
                    val = float(spec[:-1]) / 1000.0
                else:
                    val = float(spec)
            except ValueError as err:
                raise BentoMLConfigException(f"Invalid CPU resource limit '{spec}'.") from err
        else:
            raise TypeError(
                "CPU resource limit must be int, float or str."
            )

        if val < 0:
            raise BentoMLConfigException(f"Invalid CPU resource limit '{spec}'.")
        return val

