class _MediaType:
    def __init__(self, media_type_str):
        self.orig = '' if (media_type_str is None) else media_type_str
        self.full_type, self.params = parse_header_parameters(self.orig)
        self.main_type, sep, self.sub_type = self.full_type.partition('/')

    def match(self, other):
        """Return true if this MediaType satisfies the given MediaType."""
        # Type must match, unless either side is a wildcard.
        if self.main_type != '*' and other.main_type != '*' and self.main_type != other.main_type:
            return False

        # Subtype must match, unless either side is a wildcard.
        if self.sub_type != '*' and other.sub_type != '*' and self.sub_type != other.sub_type:
            return False

        # All parameters on the more specific media type must be present
        # and equal on the less specific one.
        for key, value in self.params.items():
            if key not in other.params or other.params[key] != value:
                return False

        return True

