            artifacts = source.run()

            if not artifacts:
                logger.debug(f"No artifacts returned from source '{source_name}'")
                continue

            logger.debug(f"Source '{source_name}' returned {len(artifacts)} artifacts")

            # Filter out whitelisted artifacts.
            artifacts = [a for a in artifacts if not self._is_whitelisted(a)]

            if not artifacts:
                logger.debug(f"All artifacts from source '{source_name}' were whitelisted")
                continue

            # Send artifacts to operators.
            for operator_name, operator in self.operators.items():
                logger.debug(f"Sending artifacts to operator '{operator_name}'")
                try:
                    operator.run(artifacts)
                except Exception:
                    logger.exception(f"Operator '{operator_name}' failed")

            # Update stats.
            try:
                self.statsd.incr('artifacts')
                for artifact_type, count in artifact_types(artifacts).items():
                    self.statsd.incr(artifact_type, count)
            except Exception:
                logger.exception("Failed to update statsd counters")

            # Save source state if available.
            try:
                state = getattr(source, "state", None)
                if state is not None:
                    self.statedb.save_state(source_name, state)
            except Exception:
                logger.exception(f"Failed to save state for source '{source_name}'")

    except KeyboardInterrupt:
        logger.info("Interrupted by user, exiting")
        break
    except Exception:
        logger.exception("Unhandled error in run loop")

    if not daemon:
