    check_digit = self.luhn_lookup[str(self._luhn_checksum(number))]
    return number + check_digit

def _luhn_checksum(self, number: str) -> int:
    """Compute the Luhn checksum for a number string."""
    digits = [int(d) for d in number]
    checksum = 0
    parity = len(digits) % 2
    for i, digit in enumerate(digits):
        if i % 2 == parity:
            checksum += self.luhn_lookup[str(digit)]
        else:
            checksum += digit
    return checksum % 10

