            theme.append((style_name, fg, bg))
        elif len(style_spec) == 3:
            theme.append((style_name, fg, bg, style_spec[2]))
        elif len(style_spec) == 4:
            theme.append((style_name, fg, bg, style_spec[2], style_spec[3]))
        elif len(style_spec) == 5:
