async def peek(self, size=-1):
    if size is None or size < 0:
        size = self._chunk_size

    if size == 0:
        return b''

    if self._buffer_len > self._buffer_pos:
        available = self._buffer_len - self._buffer_pos
        if size <= available:
            return self._buffer[self._buffer_pos : self._buffer_pos + size]

    # Need to pull more data, but preserve current buffer state.
    buffer = self._buffer
    buffer_len = self._buffer_len
    buffer_pos = self._buffer_pos

    try:
        async for chunk in self._iter_with_buffer(size_hint=size):
            if len(chunk) >= size:
                return chunk[:size]

            # If the iterator yields multiple chunks, accumulate until enough.
            if buffer_pos == 0 and buffer_len == 0:
                buffer = chunk
                buffer_len = len(chunk)
            else:
                buffer += chunk
                buffer_len = len(buffer)

            if buffer_len - buffer_pos >= size:
                return buffer[buffer_pos : buffer_pos + size]

        return buffer[buffer_pos:]
    finally:
        # Restore buffer state after peeking.
        self._buffer = buffer
        self._buffer_len = buffer_len
        self._buffer_pos = buffer_pos

