    return await self._read_from(self._iter_with_buffer(), size=size)

async def readexactly(self, size):
    if size < 0:
        raise ValueError('size must be non-negative')

    result = await self.read(size)
    if len(result) != size:
        raise EOFError('unexpected end of stream')
    return result

async def readline(self, size=-1):
    delimiter = b'\n'
    if size is not None and size >= 0:
        return await self._read_from(self._iter_delimited(delimiter, size_hint=size), size=size)
