async def readuntil(self, delimiter, size=-1):
    if not delimiter:
        raise ValueError('delimiter must not be empty')

    return await self._read_from(self._iter_delimited(delimiter, size_hint=size if size is not None else 0), size=size)

async def pipe(self):
