    """Control serialization/deserialization of types.

    This class controls the encoding of python types to the
    format that is expected by the DynamoDB API, as well as
    taking DynamoDB types and constructing the appropriate
    python types.

    If you want to customize this process, you can subclass
    this class and override the encoding/decoding of
    specific types.  For example::

        'foo'      (Python type)
            |
            v
        encode('foo')
            |
            v
        _encode_s('foo')
            |
            v
        {'S': 'foo'}  (Encoding sent to/received from DynamoDB)
            |
            V
        decode({'S': 'foo'})
            |
            v
        _decode_s({'S': 'foo'})
            |
            v
        'foo'     (Python type)

    """
    def _get_dynamodb_type(self, attr):
        return get_dynamodb_type(attr)

    def encode(self, attr):
        """
        Encodes a python type to the format expected
        by DynamoDB.

        """
        dynamodb_type = self._get_dynamodb_type(attr)
        if dynamodb_type == 'N':
            return {'N': self._encode_n(attr)}
        elif dynamodb_type == 'S':
            return {'S': self._encode_s(attr)}
        elif dynamodb_type == 'B':
            return {'B': self._encode_b(attr)}
        elif dynamodb_type == 'NS':
            return {'NS': self._encode_ns(attr)}
        elif dynamodb_type == 'SS':
            return {'SS': self._encode_ss(attr)}
        elif dynamodb_type == 'BS':
            return {'BS': self._encode_bs(attr)}
        elif dynamodb_type == 'BOOL':
            return {'BOOL': self._encode_bool(attr)}
        elif dynamodb_type == 'NULL':
            return {'NULL': self._encode_null(attr)}
        elif dynamodb_type == 'M':
            return {'M': self._encode_m(attr)}
        elif dynamodb_type == 'L':
            return {'L': self._encode_l(attr)}
        raise TypeError("Unsupported type: %r" % (type(attr),))

    def decode(self, attr):
        """
        Decodes a DynamoDB type to the appropriate python type.
        """
        if not isinstance(attr, Mapping) or len(attr) != 1:
            raise TypeError("DynamoDB attribute must be a mapping with one key")

        dynamodb_type, value = next(iter(attr.items()))
        if dynamodb_type == 'N':
            return self._decode_n(value)
        elif dynamodb_type == 'S':
            return self._decode_s(value)
        elif dynamodb_type == 'B':
            return self._decode_b(value)
        elif dynamodb_type == 'NS':
            return self._decode_ns(value)
        elif dynamodb_type == 'SS':
            return self._decode_ss(value)
        elif dynamodb_type == 'BS':
            return self._decode_bs(value)
        elif dynamodb_type == 'BOOL':
            return self._decode_bool(value)
        elif dynamodb_type == 'NULL':
            return self._decode_null(value)
        elif dynamodb_type == 'M':
            return self._decode_m(value)
        elif dynamodb_type == 'L':
            return self._decode_l(value)
        raise TypeError("Unsupported DynamoDB type: %r" % (dynamodb_type,))

