                for dirname, _, filenames in os.walk(path, followlinks=True):
                    for filename in filenames:
                        yield uri_scheme + os.path.join(dirname, filename)
            else:
                yield uri_scheme + path

    def _cat_file(self, path):
        path = _from_file_uri(path)
