    """
    Pop and return operation global keyword arguments, in preferred order:

    + From the current context (a direct @operator or @deploy function being called)
    + From any current @deploy context (deploy kwargs)
    + From the host data variables
    + From the config variables

    Note this function is only called directly in the @operation & @deploy decorator
    wrappers which the user should pass global arguments prefixed "_". This is to
    avoid any clashes with operation and deploy functions both internal and third
    party.

    This is a bit strange because internally pyinfra uses non-_-prefixed arguments,
    and this function is responsible for the translation between the two.

    TODO: is this weird-ness acceptable? Is it worth updating internal use to _prefix?
    """
    global_arguments: AllArguments = AllArguments()  # type: ignore[call-arg]
    popped_keys: list[str] = []

    if keys_to_check is None:
        keys_to_check = []

    # Helper to pop a key from kwargs if present, recording it.
    def _pop_key(key: str, default=default_sentinel):
        if key in kwargs:
            popped_keys.append(key)
            return kwargs.pop(key)
        return default

    # Current context values take precedence.
    if host is not None:
        current_op_global_arguments = getattr(host, "current_op_global_arguments", None) or {}
        for key in keys_to_check:
            if key in current_op_global_arguments:
                setattr(global_arguments, key, current_op_global_arguments[key])

        # Deploy context values come next.
        current_deploy_kwargs = getattr(host, "current_deploy_kwargs", None) or {}
        for key in keys_to_check:
            if key in current_deploy_kwargs and not hasattr(global_arguments, key):
                setattr(global_arguments, key, current_deploy_kwargs[key])

        # Host data variables.
        host_data = getattr(host, "data", None)
        if host_data is not None:
            for key in keys_to_check:
                if not hasattr(global_arguments, key):
                    try:
                        value = host_data[key]
                    except Exception:
                        continue
                    setattr(global_arguments, key, value)

    # Config variables are the final fallback.
    if state is not None and getattr(state, "config", None) is not None:
        config = state.config
        for key in keys_to_check:
            if not hasattr(global_arguments, key) and hasattr(config, key):
                setattr(global_arguments, key, getattr(config, key))

    # Finally, allow explicit kwargs (prefixed or not) to override everything.
    # We support both `_foo` and `foo` forms here.
    for key in list(kwargs.keys()):
        normalized_key = key[1:] if key.startswith("_") else key
        if normalized_key in keys_to_check:
            value = kwargs.pop(key)
            setattr(global_arguments, normalized_key, value)
            popped_keys.append(key)

    return global_arguments, popped_keys

