# calc target position from self.pos, pos and offset
if self.handle is None:
    raise IOError('seek on closed handle')

if offset == io.SEEK_SET:
    target = pos
elif offset == io.SEEK_CUR:
    target = self.pos + pos
elif offset == io.SEEK_END:
    target = self.size + pos
else:
    raise ValueError('invalid seek mode: {0}'.format(offset))

if target < 0:
    raise IOError('negative seek position {0}'.format(target))

# if seeking forward from current position, consume bytes if possible
if target >= self.pos:
    to_skip = target - self.pos
    if to_skip:
        self.read(to_skip)
    return self.pos

# seeking backwards: reopen stream and skip forward
self.reset()
if target:
    self.read(target)
return self.pos

