class MusicSource:
    """
        Music source proxy object
    """

    def __init__(self):
        self.logger = logging.getLogger(__name__)

    def search(self, keyword, sources_list) -> list:
        """
        Search music from multiple sources.

        Args:
            keyword: search keyword
            sources_list: iterable of source objects/classes that provide a
                          `search(keyword)` method

        Returns:
            list: merged search results from all sources
        """
        if not keyword:
            raise ParameterError("keyword is required")

        if not sources_list:
            return []

        results = []
        for source in sources_list:
            if source is None:
                continue

            try:
                # Support both instance and class-style sources
                if hasattr(source, "search") and callable(getattr(source, "search")):
                    data = source.search(keyword)
                else:
                    raise ParameterError(f"Invalid source: {source}")

                if data:
                    if isinstance(data, list):
                        results.extend(data)
                    else:
                        results.append(data)

            except Exception as e:
                self.logger.exception("Search failed for source %s: %s", source, e)

        return results

