def md5sum(self, path):
    try:
        stdout = self.invoke_hadoop(['fs', '-checksum', path],
                                    return_stdout=True)
    except CalledProcessError:
        raise IOError("Could not md5sum %s" % path)

    # Hadoop checksum output varies by version; try to extract the last
    # whitespace-separated field from the last non-empty line.
    lines = [line for line in stdout.split(b'\n') if line.strip()]
    if not lines:
        raise IOError("Unexpected output from hadoop fs -checksum: %r" %
                      stdout)

    last_line = lines[-1].split()
    if not last_line:
        raise IOError("Unexpected output from hadoop fs -checksum: %r" %
                      stdout)

    return to_unicode(last_line[-1])

