class Signal(object):
    def __init__(self):
        self._flush()

    def _flush(self):
        self._receivers = set()
        self._receiver_list = []

    def connect(self, receiver, name=None, sender=None):
        name = name or receiver.__name__
        key = (name, sender)
        if key not in self._receivers:
            self._receivers.add(key)
            self._receiver_list.append((name, receiver, sender))
        else:
            raise ValueError('receiver named %s (for sender=%s) already '
                             'connected' % (name, sender or 'any'))

    def disconnect(self, receiver=None, name=None, sender=None):
        if receiver is not None:
            name = name or receiver.__name__

        key = (name, sender)
        removed = False

        new_list = []
        for r_name, r_receiver, r_sender in self._receiver_list:
            match = False
            if receiver is not None:
                match = (r_receiver == receiver and
                         (name is None or r_name == name) and
                         (sender is None or r_sender == sender))
            else:
                match = ((name is None or r_name == name) and
                         (sender is None or r_sender == sender))

            if match and not removed:
                self._receivers.discard((r_name, r_sender))
                removed = True
                continue
            new_list.append((r_name, r_receiver, r_sender))

        self._receiver_list = new_list
        return removed

