@classmethod
def for_system(cls) -> "FixedOffset":
    """Return a FixedOffset instance for the current working timezone and
    DST conditions.
    """
    # Use the local timezone offset from UTC for the current system time.
    # time.altzone is the offset during DST, time.timezone otherwise.
    import time

    if time.daylight and time.localtime().tm_isdst > 0:
        offset_seconds = -time.altzone
    else:
        offset_seconds = -time.timezone

    return cls(offset_seconds / 60)

