self.session_likelihoods = []
self.session_geomean_likelihoods = []
self.rare_windows = {2: [], 3: []}
self.rare_window_likelihoods = {2: [], 3: []}
self.rare_windows_geo = {2: [], 3: []}
self.rare_window_likelihoods_geo = {2: [], 3: []}

for session in self.sessions:
    # Build the sequence used for scoring
    seq = list(session)
    if use_start_end_tokens:
        seq = [self.start_token] + seq + [self.end_token]

    # Convert Cmd objects to command names if needed
    seq_names = [cmd.name if isinstance(cmd, Cmd) else cmd for cmd in seq]

    # Session likelihoods
    likelihoods = []
    for i, cmd in enumerate(seq_names):
        if i == 0:
            prev = self.start_token
        else:
            prev = seq_names[i - 1]

        prior = self.prior_probs.get(cmd, self.prior_probs.get(self.unk_token, 0.0))
        trans = self.trans_probs.get(prev, {}).get(
            cmd, self.trans_probs.get(prev, {}).get(self.unk_token, 0.0)
        )
        likelihoods.append(prior * trans)

    self.session_likelihoods.append(likelihoods)

    # Geometric mean likelihood
    if likelihoods:
        prod = 1.0
        for val in likelihoods:
            prod *= max(val, 1e-300)
        self.session_geomean_likelihoods.append(prod ** (1 / len(likelihoods)))
    else:
        self.session_geomean_likelihoods.append(float("nan"))

    # Sliding window rarest windows for lengths 2 and 3
    for win_len in (2, 3):
        if len(seq_names) < win_len:
            self.rare_windows[win_len].append([])
            self.rare_window_likelihoods[win_len].append(float("nan"))
            self.rare_windows_geo[win_len].append([])
            self.rare_window_likelihoods_geo[win_len].append(float("nan"))
            continue

        windows = [seq_names[i : i + win_len] for i in range(len(seq_names) - win_len + 1)]
        window_liks = []

        for window in windows:
            w_lik = 1.0
            for j, cmd in enumerate(window):
                if j == 0:
                    prev = self.start_token
                else:
                    prev = window[j - 1]

                prior = self.prior_probs.get(cmd, self.prior_probs.get(self.unk_token, 0.0))
                trans = self.trans_probs.get(prev, {}).get(
                    cmd, self.trans_probs.get(prev, {}).get(self.unk_token, 0.0)
                )
                w_lik *= max(prior * trans, 1e-300)

            window_liks.append(w_lik)

        # Rarest window = minimum likelihood
        min_idx = min(range(len(window_liks)), key=lambda idx: window_liks[idx])
        self.rare_windows[win_len].append(windows[min_idx])
        self.rare_window_likelihoods[win_len].append(window_liks[min_idx])

        # Geometric mean likelihood for each window, then rarest
        window_geo = []
        for w_lik in window_liks:
            window_geo.append(w_lik ** (1 / win_len))
        min_geo_idx = min(range(len(window_geo)), key=lambda idx: window_geo[idx])
        self.rare_windows_geo[win_len].append(windows[min_geo_idx])
        self.rare_window_likelihoods_geo[win_len].append(window_geo[min_geo_idx])

