@classmethod
def from_payload(
    cls,
    payload: Payload,
) -> ext.PdDataFrame:
    import pandas as pd

    format = payload.meta.get("format", "default")
    if format == "pickle5":
        with_buffer = t.cast(bool, payload.meta.get("with_buffer", False))
        if with_buffer:
            bs_str = t.cast(str, payload.meta["pickle_bytes_str"])
            bs = base64.b64decode(bs_str)
            indices = t.cast(t.List[int], payload.meta["indices"])
            return t.cast("ext.PdDataFrame", pep574_loads(bs, payload.data, indices))
        return t.cast("ext.PdDataFrame", pickle.loads(payload.data))

    return t.cast("ext.PdDataFrame", pickle.loads(payload.data))

