def heads(self) -> Tuple[str, ...]:
    """All "head" revisions as strings.

    This is normally a tuple of length one,
    unless unmerged branches are present.

    :return: a tuple of string revision numbers.

    """
    return tuple(
        sorted(
            rev.revision
            for rev in self._generator()
            if rev.is_head
        )
    )

