def artifact_event(self, name, filename, metadata=None, content_type=None):
    if self.dir is None:
        return
    self.save_file(filename, name)
    artifact_entry = {"name": name}
    if metadata is not None:
        artifact_entry["metadata"] = metadata
    if content_type is not None:
        artifact_entry["content_type"] = content_type
    self.run_entry.setdefault("artifacts", [])
    self.run_entry["artifacts"].append(artifact_entry)
    self.save_json(self.run_entry, "run.json")

def log_metrics(self, metrics_by_name, info):
    if self.dir is None:
        return
    metrics_file = os.path.join(self.dir, "metrics.json")
    try:
        with open(metrics_file, "r") as f:
            metrics = json.load(f)
    except FileNotFoundError:
        metrics = {}
    metrics.update(flatten(metrics_by_name))
    with open(metrics_file, "w") as f:
        json.dump(metrics, f, sort_keys=True, indent=2)
        f.flush()

